local function NeedsRepairs(self, ...) if self.inst.components.finiteuses then return self.inst.components.finiteuses:GetPercent() < 0x1 else return self.dycOldNeedsRepairs(self, ...) end end local function Repair(self, doer, repair_item, ...) local finiteuses = self.inst.components.finiteuses local current = finiteuses and finiteuses.current local total = finiteuses and finiteuses.total local repairer = repair_item and repair_item.components.repairer local userepairvalue = repairer and repairer.userepairvalue or 0x0 local stackable = repair_item and repair_item.components.stackable if current and total and current < total and repairer and userepairvalue > 0x0 and self.repairmaterial == repairer.repairmaterial then finiteuses:SetUses(current + math.min(total - current, userepairvalue)) if stackable then stackable:Get():Remove() else repair_item:Remove() end if self.onrepaired then self.onrepaired(self.inst, doer, repair_item) end return true end return self.dycOldRepair(self, doer, repair_item, ...) end local function DYCRepairable(self) self.dycOldNeedsRepairs = self.NeedsRepairs self.NeedsRepairs = NeedsRepairs self.dycOldRepair = self.Repair self.Repair = Repair end return DYCRepairable 